const allLLMResponses    = $input.all();
const allBuildPromptData = $('Filter: text').all();

const items = [];
for (let i = 0; i < allLLMResponses.length; i++) {
  const llmResponse = allLLMResponses[i].json;
  const prevData    = allBuildPromptData[i].json;

  let title = null;
  let body  = '';

  try {
    const content   = llmResponse.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      title = parsed.title ?? null;
      body  = parsed.body  ?? content;
    } else {
      body = content;
    }
  } catch (e) {
    body = llmResponse.choices?.[0]?.message?.content ?? 'Content unavailable.';
  }

  items.push({
    json: {
      material_id: prevData.material_id,
      persona_id:  prevData.persona_id,
      post_type:   prevData.post_type,
      title,
      body,
      media_type:  'text',
      media_url:   null,
      source:      'n8n',
      sort_order:  prevData.chunk_index * 4 + 0,
    }
  });
}

return items;
